        if isCodeValid && isBusinessLineValid && isCouponActive {
            validCoupons.append((currentBusinessLine, currentCode))
        }
    }

    // Sort by business line priority and then by code
    let businessLineOrder = ["electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3]
    let sortedCoupons = validCoupons.sorted {
        let order1 = businessLineOrder[$0.businessLine]!
        let order2 = businessLineOrder[$1.businessLine]!
        if order1 != order2 {
