import "std/array"
import "std/string"
import "std/bool"

func solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Bool>): Array<String> {
    let valid_business_lines = ["electronics", "grocery", "pharmacy", "restaurant"]
    let business_line_order = {"electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3}
    let valid_coupons = []

    for i in 0..<code.length() {
        let current_code = code[i]
        let current_business_line = businessLine[i]
        let current_is_active = isActive[i]

        // Check if code is valid (non-empty and only alphanumeric + underscore)
        let is_code_valid = not current_code.empty() and current_code.matches("^[a-zA-Z0-9_]+$")

        // Check if business line is valid
        let is_business_line_valid = valid_business_lines.contains(current_business_line)

        // Check if coupon is active
        let is_coupon_active = current_is_active

        if is_code_valid and is_business_line_valid and is_coupon_active {
            valid_coupons.push({"code": current_code, "business_line": current_business_line})
        }
    }

    // Sort by business line order first, then by code
    valid_coupons.sort(func(a, b) {
        let a_order = business_line_order[a["business_line"]]
        let b_order = business_line_order[b["business_line"]]
        if a_order != b_order {
            return a_order < b_order
        } else {
            return a["code"] < b["code"]
        }
    })

    // Extract just the codes in order
    let result = []
    for coupon in valid_coupons {
        result.push(coupon["code"])
    }

    return result
}
